import React from 'react';
// import { useRouteMatch, } from 'react-router-dom';
import {
  getArticlesNews,
  getTrendingNews,
  getCategoryNews,
} from '../../api/news';
import './HomePage.scss';

export const HomePage = () => {
  const [trendingNews, setTrendingNews] = useState([]);
  const [articles, setArticles] = useState({});
  const [author, setAuthor] = useState({});
  const [datePublished, setDatePublished] = useState({});
  const [categoryNews, setCategoryNews] = useState([]);
  const [categoryArticles, setCategoryArticles] = useState({});
  const [categoryAuthor, setCategoryAuthor] = useState({});
  const [category, setCategory] = useState('');

  useEffect(() => {
    getTrendingNews().then(res => setTrendingNews(
      res.value.map((news, index) => {
        getArticlesNews(news.query.text)
          .then((art) => {
            setArticles(val => ({
              ...val,
              [news.query.text]: art[0].summary,
            }));
            setAuthor(val => ({
              ...val,
              [news.query.text]: art[0].author || 'no author',
            }));
            setDatePublished(val => ({
              ...val,
              [news.query.text]: art[0].published_date.slice(0, 10),
            }));
          });

        return (
          {
            id: index + 1,
            type: 'trending',
            name: news.query.text,
            image: news.image.url,
          });
      }),
    ));
  }, []);

  useMemo(() => {
    if (articles) {
      setTrendingNews(trendingNews
        .map(news => ({
          ...news,
          summary: articles[news.name],
          author: author[news.name],
          date: datePublished[news.name],
        })));
    }
  }, [articles, author, datePublished]);

   //console.log(trendingNews, articles, author);

  useEffect(() => {
    if (category) {
      getCategoryNews(category).then(result => setCategoryNews(
        result.value.slice(0, 2).map((news, index) => {
          getArticlesNews(news.name)
            .then((art) => {
              setCategoryArticles(val => ({
                ...val,
                [news.name]: art[0].summary,
              }));
              setCategoryAuthor(val => ({
                ...val,
                [news.name]: art[0].author || 'no author',
              }));
            });

          return (
            {
              id: index + 1,
              type: category,
              name: news.name,
              image: news.image.thumbnail.contentUrl,
              description: news.description,
              date: news.datePublished.slice(0, 10),
            });
        }),
      ));
    }
  }, [category]);

  useMemo(() => {
    if (categoryArticles) {
      setCategoryNews(categoryNews
        .map(news => ({
          ...news,
          summary: categoryArticles[news.name],
          author: categoryAuthor[news.name],
        })));
    }
  }, [categoryArticles, categoryAuthor]);

  //console.log(categoryNews, categoryArticles, categoryAuthor);

  return (
    <div className="HomePage">
      <button
        className="hom"
        type="button"
        onClick={(e) => {
          e.preventDefault();
          setCategory('sports');
          console.log(category);
        }}
      >
        Click
      </button>
      <button
        className="hom"
        type="button"
        onClick={(e) => {
          e.preventDefault();
          setCategory('');
          console.log(category);
        }}
      >
        Click
      </button>
      {/* <canvas id="canvas">{}</canvas> */}
      {/* <img
        className="source"
        src={'k'}
        width="297"
        height="179"
        alt="Foto"
      /> */}
    </div>
  );
};
